noncompliant:
// Class names not following PascalCase convention
class foo { // Noncompliant - should start with capital
    int value;
};

class my_class { // Noncompliant - uses underscore
    int data;
};

class XMLparser { // Noncompliant - should be XmlParser
    void parse();
};

compliant:
// Class names following PascalCase convention
class Foo { // Compliant
    int value;
};

class MyClass { // Compliant
    int data;
};

class XmlParser { // Compliant
    void parse();
};
